VALUES
  ('judicial-f0899a01-moex-00206', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於訴願事件涉及地方自治團體地方自治事務時，受理訴願機關應如何處理？', '["應就原處分之合法性及適當性進行審查", "若發現地方自治團體所為裁罰處分僅裁量不當時，得逕以訴願決定變更原處分之裁罰額度或處罰方法", "若發現地方自治團體所為原處分違法時，依法應撤銷原處分，或撤銷原處分並限期原處分機關另為適法 之處分", "認地方自治團體所為違法處分之撤銷對公益有重大損害，仍應駁回其訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00207', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '訴願決定機關以寄存送達方式送達訴願決定書，下列敘述何者正確？', '["訴願法就此指示訴願決定機關準用行政程序法送達之規定", "為求慎重應寄存於自治或警察機關，不得寄存於郵務機構", "自寄存完成時起即發生送達之效力", "寄存機關自收受寄存文書之日起，應保存2個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00208', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於行政訴訟之停止執行規定，下列敘述何者錯誤？', '["關於停止執行或撤銷停止執行之裁定，不得為抗告", "起訴前，如原處分或決定之執行將發生難於回復之損害，且有急迫情事者，行政法院原則上得依受處分 人之聲請，裁定停止執行", "原處分或決定之執行，原則上不因提起行政訴訟而停止", "停止執行之裁定，得停止原處分或決定之效力、處分或決定之執行或程序之續行之全部或部分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00209', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列何者適用行政訴訟法之簡易訴訟程序？', '["有關內政部移民署之行政收容事件涉訟", "學生不服私立高中對其所為記大過處分而涉訟", "不服行政機關所為新臺幣58萬元罰鍰處分而涉訟", "不服行政機關所為暫停營業處分而涉訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00210', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依實務見解，消防機關因撲滅火災導致附近民宅受損而予以補償，若受損屋主認為補償金過少時，應提起 何種訴訟類型？', '["確認訴訟", "國家賠償訴訟", "課予義務訴訟", "一般給付訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00211', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依司法院解釋意旨，如民眾向財政部國有財產署依國有財產法第52條之2申請讓售國有非公用財產類之 不動產，經該署否准時，應向何法院請求救濟？', '["行政法院", "民事法院", "懲戒法院", "憲法法庭"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00212', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於都市計畫審查訴訟之要件，下列敘述何者錯誤？', '["鄉（鎮、市）層級之地方自治團體得起訴對都市計畫表示不服", "被告機關為都市計畫之核定機關，發布機關不具有被告適格", "以在未來將發生損害為要件，如已發生損害應循國家賠償救濟", "須向都市計畫區所在地高等行政法院高等行政訴訟庭起訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00213', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '依司法院解釋意旨，國家給予受無罪判決確定而受羈押之受害人金錢補償，其性質屬於下列何者？', '["生活扶助", "特別犧牲", "社會救助", "刑事司法補助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00214', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '下列何者非屬國家賠償法之公務員？', '["公立學校教師", "市府垃圾車之駕駛", "台糖小火車之駕駛", "於上班途中公務車之駕駛"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00215', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '關於因公務員之作為所生之國家賠償責任，下列敘述何者正確？', '["適用國家賠償法之公務員，僅限於依公務人員任用法所任命之公務員", "受委託行使公權力之個人於其執行職務行使公權力時，視同委託機關之公務員", "行使公權力之行為，僅限於運用命令及強制手段干預人民自由及權利之行為", "由於我國採取國家自己責任，故公務人員是否有故意或過失在所不問"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
